// Function to get a random user agent
function getRandomUserAgent() {
  const randomIndex = Math.floor(Math.random() * USER_AGENTS.length)
  return USER_AGENTS[randomIndex]
}

// ====== 延迟执行函数 ======
// github如果不间断发送请求，很大概率会失败
function delay(time = 5000) {
  // 默认5s
  return new Promise((resolve) => setTimeout(resolve, time))
}

// ====== 带重试的请求封装 ======
// 重试3遍，每遍隔5s重试，5秒后才重新发起重试请求
// 流程：第1次请求 -> 失败 -> 等5秒 -> 第2次请求 -> 失败 -> 等5秒 -> 第3次请求 -> 仍失败 -> 返回失败结果
async function requestWithRetry(fn, stepName, maxRetries = 3) {
  let lastError = null
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      console.log(`${stepName} 第${attempt}次请求...`)
      const result = await fn()
      console.log(`${stepName} 第${attempt}次请求成功`)
      return { success: true, data: result }
    } catch (error) {
      lastError = error
      console.error(`${stepName} 第${attempt}次请求失败:`, error.message || error)
      if (attempt < maxRetries) {
        console.log(`${stepName} 等待5秒后进行第${attempt + 1}次重试...`)
        // 默认5s后再重试
        await delay()
        // delay结束，for循环继续下一轮，自动发起第attempt+1次重试
      }
    }
  }
  // 3次全部失败，返回失败结果（由调用方决定是否发邮件）
  return {
    success: false,
    error: `${stepName} 重试${maxRetries}次后仍然失败: ${lastError?.message || lastError}`
  }
}

// ====== 发送失败邮件通知（配置了email才发送，没有配置则不发送） ======
async function sendFailureEmail(emailConfig, account, errorMessage) {
  if (!emailConfig || !emailConfig.from || !emailConfig.password) {
    console.log('未配置邮件信息，跳过发送失败邮件')
    return
  }

  if (!account.email) {
    console.log(`账号 ${account.user} 未配置接收邮箱，跳过发送失败邮件`)
    return
  }

  try {
    const transporter = nodemailer.createTransport({
      host: emailConfig.host || 'smtp.163.com',
      port: emailConfig.port || 25,
      secure: emailConfig.secure || false,
      auth: {
        user: emailConfig.from,
        pass: emailConfig.password
      }
    })

    const mailOptions = {
      from: `"${emailConfig.fromName || '刷步数提醒'}" <${emailConfig.from}>`,
      to: account.email,
      subject: emailConfig.subject || '刷步数失败提醒',
      html: `
        <h3>刷步数失败通知</h3>
        <p><b>账号：</b>${account.user}</p>
        <p><b>失败原因：</b>${errorMessage}</p>
        <p><b>时间：</b>${dayjs().format('YYYY-MM-DD HH:mm:ss')}</p>
      `
    }

    await transporter.sendMail(mailOptions)
    console.log(`失败邮件已发送至 ${account.email.replace(/(.{2}).*(@.*)/, '$1****$2')}`)
  } catch (error) {
    console.error('发送失败邮件出错：', error.message || error)
  }
}

// ====== AES-128-CBC 加密函数（PKCS#7 填充） ======
function encryptData(plain) {
  const key = 'xeNtBVqzDc6tuNTh' // 16 bytes
  const iv = 'MAAAYAAAAAAAAABg' // 16 bytes
  const cipher = crypto.createCipheriv('aes-128-cbc', key, iv)
  let encrypted = cipher.update(plain, 'utf8', 'binary')
  encrypted += cipher.final('binary')
  return Buffer.from(encrypted, 'binary')
}

// 从 Location URL 提取 access code
function extractAccessCode(location) {
  const match = location.match(/access=([^&]+)/)
  return match ? match[1] : null
}

// 1、获取code码
async function getHuaMiCode(params, userAgent, virtualIp) {
  const { phone, pwd } = params

  // 请求地址
  const url = 'https://api-user.zepp.com/v2/registrations/tokens'

  // 请求头
  const headers = {
    Accept: 'application/json',
    'Accept-Language': 'zh-CN,zh;q=0.8',
    'content-type': 'application/x-www-form-urlencoded; charset=UTF-8',
    app_name: 'com.xiaomi.hm.health',
    appname: 'com.xiaomi.hm.health',
    appplatform: 'android_phone',
    'x-hm-ekv': '1',
    'hm-privacy-ceip': 'false',
    'user-agent': userAgent,
    'X-Forwarded-For': virtualIp
  }

  // 请求参数
  const loginParams = {
    emailOrPhone: phone,
    password: pwd,
    state: 'REDIRECTION',
    client_id: 'HuaMi',
    country_code: 'CN',
    token: 'access',
    redirect_uri:
      'https://s3-us-west-2.amazonaws.com/hm-registration/successsignin.html'
  }
  // 加密登录参数
  const query = querystring.stringify(loginParams)
  const data = encryptData(Buffer.from(query, 'utf8'))

  const result = await requestWithRetry(async () => {
    const response = await axios.post(url, data, {
      headers: headers,
      maxRedirects: 0,
      validateStatus: () => true
    })
    // 得到的location：其实就是redirect重定向的url，然后从重定向url中解析出 access码
    // https://s3-us-west-2.amazonaws.com/hm-registration/successsignin.html?region=us-west-2&access=ZQVBQDZOQmJaR0YyajYmWnJoBAgAAAAAAYT1aalZyUWFCcnFrUXVzNFdBQmt5RVJCQUFBQVpVUEhHaEcmcj0xMiZ0PWh1YW1pJnRpPXl5ZHNAMTYzLmNuJmg9MTczOTcxNTM1NzEwNCZpPTg2NDAwMCZ1c2VybmFtZT15eWRzyf4KPuwRhTEVaHebQRJ8kQ&country_code=CN&expiration=1740579357
    // console.log("获取重定向的url", response.request._header)
    // 从url中解析出 access码
    const location = response.headers.location
    // 从url中解析出 access码
    const code = extractAccessCode(location)
    if (!code) throw new Error('解析code码失败')
    console.log('第一步：获取code码成功：', '虚拟IP:', virtualIp)
    return code
  }, '第一步：获取code码')

  if (!result.success) return result

  // 5s 后再发送请求, 避免github问题
  await delay()
  return getHuaMiToken(result.data, params, userAgent, virtualIp)
}

// 2、获取token
async function getHuaMiToken(code, params, userAgent, virtualIp) {
  const url = 'https://account.huami.com/v2/client/login'

  // 请求头
  const headers = {
    'Content-Type': 'application/x-www-form-urlencoded;charset=UTF-8',
    'user-agent': userAgent,
    'X-Forwarded-For': virtualIp
  }

  // 请求参数
  const loginParams = {
    'allow_registration=': 'false',
    app_name: 'com.xiaomi.hm.health',
    app_version: '6.3.5',
    code: code,
    country_code: 'CN',
    device_id: '2C8B4939-0CCD-4E94-8CBA-CB8EA6E613A1',
    device_model: 'phone',
    dn: 'api-user.huami.com%2Capi-mifit.huami.com%2Capp-analytics.huami.com',
    grant_type: 'access_token',
    lang: 'zh_CN',
    os_version: '1.5.0',
    source: 'com.xiaomi.hm.health',
    third_name: 'email'
  }

  const result = await requestWithRetry(async () => {
    const response = await axios.post(url, querystring.stringify(loginParams), {
      headers
    })
    const { app_token = '', user_id = '' } = response.data.token_info || {}
    if (!app_token) {
      throw Error('获取token失败')
    }
    console.log('第二步：获取token成功：', '虚拟IP:', virtualIp)
    return { app_token, user_id }
  }, '第二步：获取token')

  if (!result.success) return result

  // 5s 后再发送请求, 避免github问题
  await delay()
  return handleRunStep({ ...result.data, step: params.step }, userAgent, virtualIp)
}

