// ====== 根据北京时间和账号配置计算步数 ======
function computedStepCount(account) {
  // 获取北京时间,在一定的时间内，刷对应的步数
  try {
    const utcHour = dayjs.utc().hour()
    const utcMinute = dayjs.utc().minute()
    const hour = (utcHour + 8) % 24

    console.log('当前UTC小时：', utcHour)
    console.log('当前北京小时：', hour)
    console.log('当前分钟数：', utcMinute)

    // 根据账号配置的 stepRanges 计算步数
    const stepRanges = account.stepRanges || {}
    let step = stepRanges.default || 26888

    if (stepRanges.morning && hour >= stepRanges.morning.hours[0] && hour < stepRanges.morning.hours[1]) {
      // 早上
      step = Math.floor(Math.random() * (stepRanges.morning.max - stepRanges.morning.min + 1)) + stepRanges.morning.min
    } else if (stepRanges.afternoon && hour >= stepRanges.afternoon.hours[0] && hour < stepRanges.afternoon.hours[1]) {
      // 下午
      step = Math.floor(Math.random() * (stepRanges.afternoon.max - stepRanges.afternoon.min + 1)) + stepRanges.afternoon.min
    } else if (stepRanges.evening && hour >= stepRanges.evening.hours[0] && hour < stepRanges.evening.hours[1]) {
      // 晚上
      step = Math.floor(Math.random() * (stepRanges.evening.max - stepRanges.evening.min + 1)) + stepRanges.evening.min
    }

    console.log('通过当前时间计算出step值为：', step)
    return step
  } catch (error) {
    throw Error(error || '北京时间获取失败')
  }
}

// ====== 主程序（支持多账号 + 失败邮件通知） ======
async function signIn() {
  const config = JSON.parse(process.env.CONFIG || '{}')
  const accounts = config.accounts || []
  const emailConfig = config.email || null
  console.log("=============> 获取账号信息", JSON.stringify(maskSensitive(config)))

  if (accounts.length === 0) {
    throw Error('未配置任何账号信息')
  }

  // 配置了email才提示，没有配置则不发送邮件
  if (emailConfig && emailConfig.from && emailConfig.password) {
    console.log('已配置邮件通知，刷步数失败将自动发送邮件提醒')
  } else {
    console.log('未配置邮件通知，刷步数失败将不会发送邮件提醒')
  }

  // 逐个账号处理
  for (let i = 0; i < accounts.length; i++) {
    const account = accounts[i]
    const accountLabel = `[账号${i + 1}/${accounts.length}: ${account.user}]`

    console.log(`\n${'='.repeat(50)}`)
    console.log(`${accountLabel} 开始处理`)
    console.log(`${'='.repeat(50)}`)

    try {
      // 根据账号配置计算步数
      const step = computedStepCount(account)

      // 为每个账号生成独立的 userAgent 和 virtualIp
      const userAgent = getRandomUserAgent()
      const virtualIp = generateIp()

      console.log(`${accountLabel} 用户代理: ${userAgent}`)
      console.log(`${accountLabel} 虚拟IP: ${virtualIp}`)

      // 发送刷步数请求（内部已包含重试逻辑：重试3遍，每遍隔5s重试）
      const result = await getHuaMiCode(
        { phone: account.user, pwd: account.pwd, step: step },
        userAgent,
        virtualIp
      )

      if (result.success) {
        console.log(`${accountLabel} 刷步数成功！`)
      } else {
        console.error(`${accountLabel} 刷步数失败：`, result.error)
        // 发送失败邮件（配置了email才发送，没有配置则不发送）
        await sendFailureEmail(emailConfig, account, result.error)
      }
    } catch (error) {
      console.error(`${accountLabel} 处理异常：`, error.message || error)
      // 发送失败邮件（配置了email才发送，没有配置则不发送）
      await sendFailureEmail(emailConfig, account, error.message || String(error))
    }

    // 账号之间间隔10秒，避免请求过快
    if (i < accounts.length - 1) {
      console.log(`\n等待5秒后处理下一个账号...`)
      await delay(10000)
    }
  }

  console.log(`\n${'='.repeat(50)}`)
  console.log('所有账号处理完成')
  console.log(`${'='.repeat(50)}`)
}

signIn()
